// NCA FFmpeg 합성 — slideshow / ai_video 모두 NCA 사용

// NCA FFmpeg는 URL에 파일 확장자가 필요
function ensureExtension(url, ext) {
  if (!url) return url;
  // URL 클래스 사용 불가 (n8n Task Runner 제한)
  const qIdx = url.indexOf('?');
  const path = qIdx >= 0 ? url.substring(0, qIdx) : url;
  if (/\.(jpg|jpeg|png|gif|webp|mp4|mp3|wav|m4a)$/i.test(path)) return url;
  return url + (url.includes('?') ? '&' : '?') + 'ext=.' + ext;
}
const job = $input.first().json;
const productionMode = job.production_mode || 'ai_video';
const BGM_URL = 'http://76.13.182.180:9000/audio/bgm_new.mp3';
const SFX_URL = 'http://76.13.182.180:9000/audio/sfx_ppook.wav';

function esc(t) {
  if (!t) return '';
  return t.replace(/[\u{1F600}-\u{1FAFF}\u{200D}\u{20E3}\u{FE0F}]/gu,'').trim()
    .replace(/\\/g,'\\\\').replace(/'/g,'\u2019').replace(/"/g,'\u201D')
    .replace(/:/g,'\\:').replace(/;/g,'\;').replace(/,/g,'\\,')
    .replace(/\[/g,'\\[').replace(/\]/g,'\\]').replace(/\n/g,' ');
}
function wrap(t, max) {
  if (!t || t.replace(/\s+/g,'').length <= max) return t || '';
  const mid = Math.floor(t.length / 2);
  let best = -1, minD = t.length;
  for (let i = 1; i < t.length - 1; i++) {
    if (t[i] === ' ' && Math.abs(i - mid) < minD) { minD = Math.abs(i - mid); best = i; }
  }
  return best > 0 ? t.substring(0, best).trim() + '\n' + t.substring(best).trim() : t;
}

const subtitles = job.tts_subtitles || [];
const audioUrl = job.tts_audio_url;
const totalDuration = job.total_duration || 10;

let inputs = [];
let idx = 0;

if (productionMode === 'slideshow') {
  // ===== SLIDESHOW: 이미지 슬라이드 =====
  const imgUrls = job.slide_image_urls || [];
  if (imgUrls.length === 0) throw new Error('slideshow: 이미지 없음');
  const imgDur = job.img_duration || (totalDuration / imgUrls.length);

  for (const url of imgUrls) {
    inputs.push({ file_url: ensureExtension(url, 'jpg'), options: [
      { option: '-loop', argument: '1' },
      { option: '-framerate', argument: '30' },
      { option: '-t', argument: imgDur.toFixed(2) }
    ] });
    idx++;
  }

  // TTS 오디오
  const audioIdx = idx;
  if (audioUrl) { inputs.push({ file_url: ensureExtension(audioUrl, 'mp3'), options: [] }); idx++; }

  // BGM
  const bgmIdx = idx;
  inputs.push({ file_url: BGM_URL, options: [{ option: '-stream_loop', argument: '-1' }] }); idx++;

  // SFX (이미지 전환마다)
  const sfxList = [];
  for (let i = 1; i < imgUrls.length; i++) {
    inputs.push({ file_url: SFX_URL, options: [] });
    sfxList.push({ idx: idx, ms: Math.round(i * imgDur * 1000) }); idx++;
  }

  let fp = [];
  // 비디오 스케일 + concat
  for (let i = 0; i < imgUrls.length; i++) {
    fp.push(`[${i}:v]scale=1080:1080:force_original_aspect_ratio=increase,crop=1080:1080,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black,setsar=1,fps=30[v${i}]`);
  }
  fp.push(`${imgUrls.map((_,i) => `[v${i}]`).join('')}concat=n=${imgUrls.length}:v=1:a=0[vconcat]`);

  // 오디오
  if (audioUrl) fp.push(`[${audioIdx}:a]atrim=duration=${totalDuration.toFixed(2)},asetpts=PTS-STARTPTS[tts_raw]`);
  const bgmTotalDur = totalDuration + 2;
  fp.push(`[${bgmIdx}:a]atrim=duration=${bgmTotalDur.toFixed(2)},asetpts=PTS-STARTPTS,afade=t=out:st=${Math.max(0, totalDuration - 2).toFixed(2)}:d=2[bgm]`);

  // SFX 필터
  if (sfxList.length > 0) {
    sfxList.forEach((s, i) => fp.push(`[${s.idx}:a]atrim=duration=0.3,asetpts=PTS-STARTPTS,volume=0.6,adelay=${s.ms}|${s.ms}[sfx${i}]`));
    fp.push(`${sfxList.map((_,i) => `[sfx${i}]`).join('')}amix=inputs=${sfxList.length}:duration=longest:normalize=0[sfx_mix]`);
    if (audioUrl) {
      fp.push(`[tts_raw][bgm][sfx_mix]amix=inputs=3:duration=longest:weights=1 1 0.8:normalize=0[amain]`);
    } else {
      fp.push(`[bgm][sfx_mix]amix=inputs=2:duration=longest:weights=1 0.8:normalize=0[amain]`);
    }
  } else {
    if (audioUrl) {
      fp.push(`[tts_raw][bgm]amix=inputs=2:duration=longest:weights=1 1:normalize=0[amain]`);
    } else {
      fp.push(`[${bgmIdx}:a]acopy[amain]`);
    }
  }

  // 자막 drawtext
  let ov = '[vconcat]null';
  for (const sub of subtitles) {
    const st = esc(wrap(sub.text, 12));
    if (!st) continue;
    ov += `,drawtext=expansion=none:text='${st}':fontsize=70:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:borderw=4:bordercolor=black:enable='between(t\\,${sub.start.toFixed(2)}\\,${(sub.start + sub.duration).toFixed(2)})'`;
  }
  ov += '[vfinal]';
  fp.push(ov);

  const payload = {
    inputs,
    filters: [{ filter: fp.join(';') }],
    outputs: [{ options: [
      { option: '-map', argument: '[vfinal]' }, { option: '-map', argument: '[amain]' },
      { option: '-c:v', argument: 'libx264' }, { option: '-preset', argument: 'fast' }, { option: '-crf', argument: '23' },
      { option: '-c:a', argument: 'aac' }, { option: '-b:a', argument: '192k' },
      { option: '-pix_fmt', argument: 'yuv420p' }, { option: '-movflags', argument: '+faststart' },
      { option: '-t', argument: totalDuration.toFixed(2) }
    ], file_name: 'ao_slideshow.mp4' }]
  };

  const ncaResp = await this.helpers.httpRequest({
    method: 'POST', url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: { 'x-api-key': 'nca-sagong-2026', 'Content-Type': 'application/json' },
    body: payload, json: true, timeout: 600000
  });

  let videoUrl = '';
  if (Array.isArray(ncaResp.response)) videoUrl = ncaResp.response[0]?.file_url || '';
  else if (typeof ncaResp.response === 'string') videoUrl = ncaResp.response;
  else videoUrl = ncaResp.output_url || ncaResp.url || ncaResp.video_url || '';
  if (!videoUrl) throw new Error('NCA 슬라이드쇼 URL 없음: ' + JSON.stringify(ncaResp).substring(0, 500));

  return [{ json: { id: 'nca-slideshow', status: 'succeeded', url: videoUrl } }];

} else {
  // ===== AI_VIDEO: Kling 영상 + TTS + BGM + SFX → NCA FFmpeg =====
  const klingVideoUrl = job.kling_video_url;
  if (!klingVideoUrl) throw new Error('ai_video: kling_video_url 없음');
  const videoDuration = job.total_duration || parseInt(job.clip_duration) || 8;

  // Kling 영상 입력
  inputs.push({ file_url: ensureExtension(klingVideoUrl, 'mp4'), options: [] }); idx++;

  // TTS 오디오
  const audioIdx = idx;
  if (audioUrl) { inputs.push({ file_url: ensureExtension(audioUrl, 'mp3'), options: [] }); idx++; }

  // BGM
  const bgmIdx = idx;
  inputs.push({ file_url: BGM_URL, options: [{ option: '-stream_loop', argument: '-1' }] }); idx++;

  // SFX (영상 시작 시 1개)
  inputs.push({ file_url: SFX_URL, options: [] });
  const sfxIdx = idx; idx++;

  let fp = [];
  // 비디오 스케일
  fp.push(`[0:v]scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920,setsar=1,fps=30[vscaled]`);

  // 오디오
  if (audioUrl) fp.push(`[${audioIdx}:a]atrim=duration=${totalDuration.toFixed(2)},asetpts=PTS-STARTPTS[tts_raw]`);
  const bgmTotalDur = totalDuration + 2;
  fp.push(`[${bgmIdx}:a]atrim=duration=${bgmTotalDur.toFixed(2)},asetpts=PTS-STARTPTS,afade=t=out:st=${Math.max(0, totalDuration - 2).toFixed(2)}:d=2[bgm]`);

  // SFX
  fp.push(`[${sfxIdx}:a]atrim=duration=0.3,asetpts=PTS-STARTPTS,volume=0.6,adelay=500|500[sfx0]`);

  if (audioUrl) {
    fp.push(`[tts_raw][bgm][sfx0]amix=inputs=3:duration=longest:weights=1 1 0.8:normalize=0[amain]`);
  } else {
    fp.push(`[bgm][sfx0]amix=inputs=2:duration=longest:weights=1 0.8:normalize=0[amain]`);
  }

  // 자막
  let ov = '[vscaled]null';
  for (const sub of subtitles) {
    const st = esc(wrap(sub.text, 12));
    if (!st) continue;
    ov += `,drawtext=expansion=none:text='${st}':fontsize=70:fontcolor=white:fontfile=/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf:x=(w-tw)/2:y=h-280:borderw=4:bordercolor=black:enable='between(t\\,${sub.start.toFixed(2)}\\,${(sub.start + sub.duration).toFixed(2)})'`;
  }
  ov += '[vfinal]';
  fp.push(ov);

  const payload = {
    inputs,
    filters: [{ filter: fp.join(';') }],
    outputs: [{ options: [
      { option: '-map', argument: '[vfinal]' }, { option: '-map', argument: '[amain]' },
      { option: '-c:v', argument: 'libx264' }, { option: '-preset', argument: 'fast' }, { option: '-crf', argument: '23' },
      { option: '-c:a', argument: 'aac' }, { option: '-b:a', argument: '192k' },
      { option: '-pix_fmt', argument: 'yuv420p' }, { option: '-movflags', argument: '+faststart' },
      { option: '-t', argument: totalDuration.toFixed(2) }
    ], file_name: 'ao_video.mp4' }]
  };

  const ncaResp = await this.helpers.httpRequest({
    method: 'POST', url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: { 'x-api-key': 'nca-sagong-2026', 'Content-Type': 'application/json' },
    body: payload, json: true, timeout: 600000
  });

  let videoUrl = '';
  if (Array.isArray(ncaResp.response)) videoUrl = ncaResp.response[0]?.file_url || '';
  else if (typeof ncaResp.response === 'string') videoUrl = ncaResp.response;
  else videoUrl = ncaResp.output_url || ncaResp.url || ncaResp.video_url || '';
  if (!videoUrl) throw new Error('NCA ai_video URL 없음: ' + JSON.stringify(ncaResp).substring(0, 500));

  return [{ json: { id: 'nca-aivideo', status: 'succeeded', url: videoUrl } }];
}

/* === 기존 Creatomate 코드 (보존) ===
// Creatomate API 렌더링 코드는 NCA FFmpeg로 교체됨
// 필요 시 롤백 가능
=== 기존 Creatomate 코드 끝 === */

// NCA 응답: 이미 완료, 폴링 불필요 (slideshow + ai_video 모두)
const renderResponse = $input.first().json;
if (renderResponse.status === 'succeeded' && renderResponse.url) {
  const prevData = $('멀티씬 순차 처리').first().json;
  return [{ json: {
    ...prevData,
    rendered_video_url: renderResponse.url,
    render_id: renderResponse.id || 'nca'
  } }];
}

// fallback: Creatomate 폴링 (비활성화 상태이지만 보존)
const renderId = renderResponse.id;
const apiKey = $env.CREATOMATE_API_KEY;
if (!renderId || !apiKey) throw new Error('render_id 또는 API key 없음');

for (let i = 0; i < 60; i++) {
  await new Promise(r => setTimeout(r, 10000));
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: `https://api.creatomate.com/v1/renders/${renderId}`,
    headers: { 'Authorization': `Bearer ${apiKey}` },
    json: true
  });
  if (resp.status === 'succeeded') {
    const prevData = $('멀티씬 순차 처리').first().json;
    return [{ json: { ...prevData, rendered_video_url: resp.url, render_id: renderId } }];
  }
  if (resp.status === 'failed') throw new Error('Creatomate 렌더 실패: ' + (resp.error_message || ''));
}
throw new Error('렌더링 타임아웃 (600초)');

// ✅ 에러 핸들러 — 재시도 로직
const error = $input.first().json;
const jobId = $('큐에서 Job 꺼내기').first().json?.id;

if (!jobId) return [];

return [{
  json: {
    job_id: jobId,
    error_message: error.message || JSON.stringify(error),
    timestamp: new Date().toISOString()
  }
}];

// 영상/슬라이드쇼 처리 — use_mode + generated_images + kie.ai TTS
const job = $input.first().json;
const productionMode = job.production_mode || 'ai_video';
let files = job.files || [];
if (typeof files === 'string') { try { files = JSON.parse(files); } catch(e) { files = []; } }

let generatedImages = job.generated_images || [];
if (typeof generatedImages === 'string') { try { generatedImages = JSON.parse(generatedImages); } catch(e) { generatedImages = []; } }

const apiKey = $env.KIEAI_API_KEY;
const promptBase = job.prompt_en || job.prompt_to_engine || job.prompt_p1;

// kie.ai 폴링 (공통)
async function pollTask(taskId) {
  for (let i = 0; i < 90; i++) {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://api.kie.ai/api/v1/jobs/recordInfo?taskId=${taskId}`,
      headers: { 'Authorization': `Bearer ${apiKey}` },
      json: true
    });
    const state = resp?.data?.state;
    if (state === 'success') {
      const result = JSON.parse(resp.data.resultJson || '{}');
      return result.resultUrls?.[0] || null;
    }
    if (state === 'failed' || state === 'fail') {
      throw new Error(`Task 실패: ${resp.data.failMsg || state}`);
    }
    await new Promise(r => setTimeout(r, 10000));
  }
  throw new Error('Task 타임아웃 (900초)');
}

// kie.ai 이미지 생성
async function generateImage(prompt) {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: { model: 'nano-banana-pro', input: { prompt: prompt, aspect_ratio: '9:16' } },
    json: true
  });
  const taskId = resp?.data?.taskId;
  if (!taskId) throw new Error('이미지 생성 taskId 없음');
  return await pollTask.call(this, taskId);
}

// kie.ai TTS 생성 (ElevenLabs multilingual v2)
async function generateTTS(text) {
  if (!text) return { audioUrl: null, duration: 0 };
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.kie.ai/api/v1/jobs/createTask',
    headers: { 'Authorization': `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: {
      model: 'elevenlabs/text-to-speech-multilingual-v2',
      input: { text: text, voice_id: 'EXAVITQu4vr4xnSDxMaL' }
    },
    json: true
  });
  const taskId = resp?.data?.taskId;
  if (!taskId) throw new Error('TTS taskId 없음');
  const audioUrl = await pollTask.call(this, taskId);
  // 한국어 약 4.5자/초 기준으로 추정 (tempo 보정 없음)
  const estimatedDuration = Math.max(3, text.replace(/\s+/g, '').length / 4.5);
  return { audioUrl, duration: estimatedDuration };
}

// use_mode별 이미지 처리
async function processFilesByUseMode(fileList) {
  const imageUrls = [];
  for (const f of fileList) {
    if (f.type !== 'image') continue;
    const mode = f.use_mode || 'direct';
    if (mode === 'direct') {
      if (f.url) imageUrls.push(f.url);
    } else if (mode === 'generate') {
      // 분석결과 기반 비슷한 이미지 생성
      const prompt = f.vision_analysis
        ? `Create a similar image: ${f.vision_analysis}. High quality, cinematic.`
        : 'Beautiful cinematic image, high quality, 9:16 aspect ratio.';
      const url = await generateImage.call(this, prompt);
      if (url) imageUrls.push(url);
    } else if (mode === 'analysis_only') {
      // auto_prompt 기반 완전 새 이미지 생성
      const prompt = f.auto_prompt || f.vision_analysis || 'Cinematic image, high quality.';
      const url = await generateImage.call(this, prompt);
      if (url) imageUrls.push(url);
    }
  }
  return imageUrls;
}

// 자막 세그먼트 생성 (문장 분리 + 글자수 비율 배분)
function buildSubtitleSegments(text, totalDuration) {
  const sentences = text.split(/(?<=[.!?\u3002\uFF01\uFF1F])\s*/).filter(s => s.trim());
  if (sentences.length === 0) return [];
  const totalChars = sentences.reduce((sum, s) => sum + s.replace(/\s+/g, '').length, 0);
  let offset = 0;
  return sentences.map(s => {
    const chars = s.replace(/\s+/g, '').length;
    const dur = totalChars > 0 ? (chars / totalChars) * totalDuration : totalDuration / sentences.length;
    const seg = { text: s.trim(), start: offset, duration: dur };
    offset += dur;
    return seg;
  });
}

// ===== SLIDESHOW 모드 =====
if (productionMode === 'slideshow') {
  // use_mode별 이미지 처리
  const processedImages = await processFilesByUseMode.call(this, files);
  // generated_images 합류
  const allImages = [...processedImages, ...generatedImages].filter(Boolean);
  if (allImages.length === 0) throw new Error('slideshow: 사용 가능한 이미지 없음');

  // 나레이션 텍스트
  const ttsText = (job.prompt_p1 || job.topic || '').replace(/<[^>]*>?/gm, '');
  if (!ttsText) throw new Error('slideshow: 나레이션 텍스트(prompt_p1 또는 topic) 없음');

  // TTS 생성
  const tts = await generateTTS.call(this, ttsText);
  if (!tts.audioUrl) throw new Error('TTS 생성 실패');

  const audioDuration = tts.duration;
  const imgDuration = audioDuration / allImages.length;
  const subtitles = buildSubtitleSegments(ttsText, audioDuration);

  return [{
    json: {
      ...job,
      production_mode: 'slideshow',
      slide_image_urls: allImages,
      tts_audio_url: tts.audioUrl,
      tts_duration: audioDuration,
      tts_text: ttsText,
      tts_subtitles: subtitles,
      img_duration: imgDuration,
      scene_results: allImages.map((url, i) => ({
        index: i, image_url: url, start: i * imgDuration, duration: imgDuration, type: 'slide'
      })),
      total_scenes: allImages.length,
      total_duration: audioDuration
    }
  }];
}

// ===== AI_VIDEO 모드 =====
// use_mode별 이미지 처리
const processedImages = await processFilesByUseMode.call(this, files);
// generated_images 합류
